/* STATIC FUNCTIONS **********************************************************/

/**
 * Creates a new default instance of the transaction_body.
 * @return A new instance of the transaction_body.
 */
static cardano_transaction_body_t*
new_default_transaction_body()
{
  cardano_transaction_body_t* transaction_body = NULL;
  cardano_cbor_reader_t*      reader           = cardano_cbor_reader_from_hex(CONWAY_CBOR_WITH_SETS, strlen(CONWAY_CBOR_WITH_SETS));
  cardano_error_t             result           = cardano_transaction_body_from_cbor(reader, &transaction_body);

  EXPECT_THAT(result, CARDANO_SUCCESS);

  cardano_cbor_reader_unref(&reader);

  cardano_transaction_body_clear_cbor_cache(transaction_body);

  return transaction_body;
};

/**
 * Decodes the given transaction body CBOR hex, clears the CBOR cache and re-encodes it,
 * expecting the produced bytes to be identical to the input.
 *
 * @param cbor The transaction body CBOR hex string to round trip.
 */
static void
expect_byte_exact_round_trip(const char* cbor)
{
  cardano_transaction_body_t* transaction_body = NULL;
  cardano_cbor_reader_t*      reader           = cardano_cbor_reader_from_hex(cbor, strlen(cbor));

  EXPECT_EQ(cardano_transaction_body_from_cbor(reader, &transaction_body), CARDANO_SUCCESS);

  cardano_transaction_body_clear_cbor_cache(transaction_body);

  cardano_cbor_writer_t* writer = cardano_cbor_writer_new();

  EXPECT_EQ(cardano_transaction_body_to_cbor(transaction_body, writer), CARDANO_SUCCESS);

  size_t hex_size = cardano_cbor_writer_get_hex_size(writer);
  char*  hex      = (char*)malloc(hex_size);

  EXPECT_EQ(cardano_cbor_writer_encode_hex(writer, hex, hex_size), CARDANO_SUCCESS);
  EXPECT_STREQ(hex, cbor);

  cardano_transaction_body_unref(&transaction_body);
  cardano_cbor_reader_unref(&reader);
  cardano_cbor_writer_unref(&writer);
  free(hex);
};

/**
 * Decodes the given CBOR hex string and expects the decode to fail with the given error.
 *
 * @param cbor The CBOR hex string to decode.
 * @param expected_error The error the decode is expected to fail with.
 */
static void
expect_decode_failure(const char* cbor, const cardano_error_t expected_error)
{
  cardano_transaction_body_t* transaction_body = NULL;
  cardano_cbor_reader_t*      reader           = cardano_cbor_reader_from_hex(cbor, strlen(cbor));

  cardano_error_t result = cardano_transaction_body_from_cbor(reader, &transaction_body);

  EXPECT_EQ(result, expected_error);
  EXPECT_EQ(transaction_body, (cardano_transaction_body_t*)nullptr);

  cardano_cbor_reader_unref(&reader);
};

/**
 * Loads the body of the Dijkstra golden transaction vector as a CBOR hex string.
 *
 * The vector path is derived from this source file location so the test does not depend
 * on the working directory the binary is launched from.
 *
 * @return The CBOR hex string of the golden transaction body.
 */
static std::string
load_golden_body_hex()
{
  const std::filesystem::path path = std::filesystem::path(__FILE__).parent_path().parent_path() / "vectors" / "dijkstra" / "golden" / "tx.cbor";

  std::ifstream     stream(path, std::ios::binary);
  std::vector<char> bytes((std::istreambuf_iterator<char>(stream)), std::istreambuf_iterator<char>());

  EXPECT_FALSE(bytes.empty());

  cardano_cbor_reader_t* reader = cardano_cbor_reader_new((const byte_t*)bytes.data(), bytes.size());

  int64_t array_size = 0;
  EXPECT_EQ(cardano_cbor_reader_read_start_array(reader, &array_size), CARDANO_SUCCESS);

  cardano_buffer_t* body_bytes = NULL;
  EXPECT_EQ(cardano_cbor_reader_read_encoded_value(reader, &body_bytes), CARDANO_SUCCESS);

  const size_t      hex_size = cardano_buffer_get_hex_size(body_bytes);
  std::vector<char> hex(hex_size);

  EXPECT_EQ(cardano_buffer_to_hex(body_bytes, hex.data(), hex.size()), CARDANO_SUCCESS);

  cardano_buffer_unref(&body_bytes);
  cardano_cbor_reader_unref(&reader);

  return std::string(hex.data());
};

/* UNIT TESTS ****************************************************************/

TEST(cardano_transaction_body_ref, increasesTheReferenceCount)
{
  // Arrange
  cardano_transaction_body_t* transaction_body = new_default_transaction_body();
  EXPECT_NE(transaction_body, nullptr);

  // Act
  cardano_transaction_body_ref(transaction_body);

  // Assert
  EXPECT_THAT(transaction_body, testing::Not((cardano_transaction_body_t*)nullptr));
  EXPECT_EQ(cardano_transaction_body_refcount(transaction_body), 2);

  // Cleanup - We need to unref twice since one reference was added.
  cardano_transaction_body_unref(&transaction_body);
  cardano_transaction_body_unref(&transaction_body);
}

TEST(cardano_transaction_body_ref, doesntCrashIfGivenANullPtr)
{
  // Act
  cardano_transaction_body_ref(nullptr);
}

TEST(cardano_transaction_body_unref, doesntCrashIfGivenAPtrToANullPtr)
{
  // Arrange
  cardano_transaction_body_t* transaction_body = nullptr;

  // Act
  cardano_transaction_body_unref(&transaction_body);
}

TEST(cardano_transaction_body_unref, doesntCrashIfGivenANullPtr)
{
  // Act
  cardano_transaction_body_unref((cardano_transaction_body_t**)nullptr);
}

TEST(cardano_transaction_body_unref, decreasesTheReferenceCount)
{
  // Arrange
  cardano_transaction_body_t* transaction_body = new_default_transaction_body();
  EXPECT_NE(transaction_body, nullptr);

  // Act
  cardano_transaction_body_ref(transaction_body);
  size_t ref_count = cardano_transaction_body_refcount(transaction_body);

  cardano_transaction_body_unref(&transaction_body);
  size_t updated_ref_count = cardano_transaction_body_refcount(transaction_body);

  // Assert
  EXPECT_EQ(ref_count, 2);
  EXPECT_EQ(updated_ref_count, 1);

  // Cleanup
  cardano_transaction_body_unref(&transaction_body);
}

TEST(cardano_transaction_body_unref, freesTheObjectIfReferenceReachesZero)
{
  // Arrange
  cardano_transaction_body_t* transaction_body = new_default_transaction_body();
  EXPECT_NE(transaction_body, nullptr);

  // Act
  cardano_transaction_body_ref(transaction_body);
  size_t ref_count = cardano_transaction_body_refcount(transaction_body);

  cardano_transaction_body_unref(&transaction_body);
  size_t updated_ref_count = cardano_transaction_body_refcount(transaction_body);

  cardano_transaction_body_unref(&transaction_body);

  // Assert
  EXPECT_EQ(ref_count, 2);
  EXPECT_EQ(updated_ref_count, 1);
  EXPECT_EQ(transaction_body, (cardano_transaction_body_t*)nullptr);

  // Cleanup
  cardano_transaction_body_unref(&transaction_body);
}

TEST(cardano_transaction_body_refcount, returnsZeroIfGivenANullPtr)
{
  // Act
  size_t ref_count = cardano_transaction_body_refcount(nullptr);

  // Assert
  EXPECT_EQ(ref_count, 0);
}

