TEST(cardano_transaction_body_from_cbor, returnsErrorIfMemoryAllocationFailsOnDijkstraKeys)
{
  // Arrange
  const char* vectors[] = {
    GUARDS_CREDENTIAL_FORM_BODY,
    SUB_TRANSACTIONS_TAGGED_BODY,
    REQUIRED_TOP_LEVEL_GUARDS_BODY,
    DIRECT_DEPOSITS_BODY,
    ACCOUNT_BALANCE_INTERVALS_BODY
  };

  for (size_t vector = 0U; vector < (sizeof(vectors) / sizeof(vectors[0])); ++vector)
  {
    for (int i = 0; i < 16; ++i)
    {
      cardano_transaction_body_t* transaction_body = NULL;
      cardano_cbor_reader_t*      reader           = cardano_cbor_reader_from_hex(vectors[vector], strlen(vectors[vector]));

      reset_allocators_run_count();
      set_malloc_limit(i);
      cardano_set_allocators(fail_malloc_at_limit, realloc, free);

      // Act
      cardano_error_t result = cardano_transaction_body_from_cbor(reader, &transaction_body);

      // Assert
      EXPECT_EQ(result, CARDANO_ERROR_MEMORY_ALLOCATION_FAILED);
      EXPECT_EQ(transaction_body, (cardano_transaction_body_t*)nullptr);

      reset_allocators_run_count();
      reset_limited_malloc();
      cardano_set_allocators(malloc, realloc, free);

      cardano_cbor_reader_unref(&reader);
    }
  }
}

