  cardano_blake2b_hash_t* hash = NULL;

  EXPECT_EQ(cardano_blake2b_hash_set_get(required_signers, 0, &hash), CARDANO_SUCCESS);

  const char* expected_hash_hex = "00112233445566778899aabbccddeeff00112233445566778899aabb";
  size_t      hex_size          = cardano_blake2b_hash_get_hex_size(hash);
  char*       hex               = (char*)malloc(hex_size);

  EXPECT_EQ(cardano_blake2b_hash_to_hex(hash, hex, hex_size), CARDANO_SUCCESS);
  EXPECT_STREQ(hex, expected_hash_hex);

  // Cleanup
  cardano_transaction_body_unref(&transaction_body);
  cardano_guard_set_unref(&guards);
  cardano_blake2b_hash_set_unref(&required_signers);
  cardano_blake2b_hash_unref(&hash);
  cardano_cbor_reader_unref(&reader);
